{
  "name": "Sage PLUS (SHIP - State Health Insurance Assistance Program)",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits. Open to all regardless of income.",
    "asset_limits": "No asset limits or tests apply.",
    "other_requirements": ["Must have Medicare or be Medicare-eligible", "Hawaii resident", "Includes beneficiaries, families, caregivers, agencies, and soon-to-be retirees"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one counseling, consultations, referrals, and presentations on Medicare coverage, Medigap/Medicare Advantage options, prescription drug coverage, travel coverage, resources to help pay Medicare costs, Medicaid, and long-term care; provided by trained certified volunteer counselors over phone, virtually via Zoom, or in-person if necessary; no charge to the public",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 808-586-7299 (Oahu) or toll-free 1-888-875-9229; TTY: 1-866-810-4379", "Website: https://www.hawaiiship.org (request counseling)", "In-person: Accommodations available upon request via phone"],
    "processing_time": "Immediate scheduling for phone/virtual counseling; in-person as needed",
    "waitlist": null,
    "forms": [],
    "documents": ["Medicare card or number recommended for counseling; no formal application or documents required to start"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Local counselors available statewide with Oahu-specific helpline, but services uniform via toll-free access; no differences in providers, offices, or wait times noted by region",
    "offices_or_providers": ["Administered statewide by Hawaii Department of Health, Executive Office on Aging; volunteer-based with local certified counselors"]
  },
  "official_source": "https://www.hawaiiship.org",
  "gotchas": ["Not a financial aid or healthcare provider program—only free counseling and information assistance, not direct payments or services; people often confuse with Medicaid/Med-Quest which have strict income/asset limits; requires Medicare enrollment for full relevance; volunteer-based so availability depends on counselor schedules"],
  "data_shape_notes": "no income or asset test; volunteer counseling service only, not benefits-paying program; statewide uniform access via phone/virtual with no formal application"
}

{
  "name": "Executive Office on Aging Family Caregiver Support Program",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict income limits; services available regardless of income, but priority given to those with greatest economic and social needs, focusing on low-income minorities, limited English-speaking, and the disabled[6].",
    "asset_limits": "No asset limits mentioned in available sources.",
    "other_requirements": ["Care recipient must be 60 years or older with impairments in at least 2 ADLs or IADLs and an unmet need[1]", "Family caregiver must be unpaid and providing care to eligible senior[1][3]", "Special populations: Adults 55+ caring for non-child over 18 with developmental disabilities; grandparents/relatives 55+ caring for children 18 and under[3]", "Native Hawaiian-specific: Caregiver of Native Hawaiian 60+ with chronic illness/disability, or Native Hawaiian grandparent/relative caring for child 18 or under[3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Information and assistance, individual counseling, support groups and training, respite (in-home or out-of-home such as personal care, homemaker, adult day care), supplemental services; case management, care planning, linkages to community services[1][2][7]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Oahu 808-768-7700 (Elderly Affairs Division), Neighbor Islands 1-800-570-1101[1][6]", "Website: https://health.hawaii.gov/eoa/ or https://hawaiiadrc.org[2][4]", "In-person: Contact local Area Agency on Aging offices (e.g., Honolulu Elderly Affairs Division)[6]", "Aging & Disability Resource Center (ADRC): 808-643-2372[5]"],
    "processing_time": "Not specified in sources.",
    "waitlist": "Services depend on eligibility and availability due to limited funding; priority for greatest needs may imply waitlists[6]",
    "forms": ["No specific form names/numbers identified"],
    "documents": ["Not explicitly listed; prepare proof of age, residency, caregiver relationship, and description of care needs/impairments (inferred from assessment processes)[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered through four county Area Agencies on Aging (Honolulu, Hawaii, Maui, Kauai)",
    "regional_variations": "Each county AAA plans and administers services differently; e.g., Honolulu-specific services like case management in upper Kalihi Valley; different contacts and providers per island[1][6]",
    "offices_or_providers": ["Honolulu: Elderly Affairs Division (808-768-7700, elderlyaffairs.com)[6]", "Neighbor Islands: 1-800-570-1101[1]", "Statewide ADRC via EOA[4]"]
  },
  "official_source": "https://health.hawaii.gov/eoa/",
  "gotchas": ["Funding prioritizes greatest needs (low-income, minorities, limited English, disabled), so higher-income may be deprioritized or wait longer[6]", "Services vary by county AAA and availability; not all services in every location[6]", "Must have unpaid caregiver and specific impairments (2+ ADLs/IADLs); independent seniors without caregiver may not qualify[1]", "Respite and other services depend on eligibility assessment, not guaranteed[7]"],
  "data_shape_notes": "Administered statewide via 4 county AAAs with priority tiers for greatest needs; no fixed income/asset tests but funding-limited; benefits include caregiver-specific respite/counseling plus linkages"
}

{
  "name": "Legal Aid Society of Hawaii Elder Law Program",
  "eligibility": {
    "age": 60,
    "income_limits": "Low-income required, but exact dollar amounts or household size table not specified in available sources; cases evaluated individually based on limited income[4][7].",
    "asset_limits": "Not specified; low assets implied as part of low-income evaluation, but no details on what counts or exemptions[4][7].",
    "other_requirements": ["Low-income individuals or families", "Civil legal needs only (e.g., no criminal or fee-generating cases)", "Priority to most needy due to limited resources[4][7]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal advice; advance planning services (specifics like advance health care directives, powers of attorney, wills not detailed for this program but implied in elder law context); areas include family, housing, consumer, public benefits[4][6][7].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: 808-536-4302 (Oahu) or 1-800-499-4302 (neighbor islands), Monday-Friday 9:00AM-11:30AM & 1:00PM-3:30PM[4][7]", "Website: https://www.legalaidhawaii.org/elder-law-services.html[4]", "No walk-in intake; physical offices not open to public, but accommodations for current clients[7]", "Mail or in-person not specified for initial intake"],
    "processing_time": "Not specified",
    "waitlist": "Not specified; priority given to most needy due to limited resources, implying potential delays[4][7]",
    "forms": ["Not specified"],
    "documents": ["Not specified; prepare income and asset details for evaluation"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None specified; toll-free number for neighbor islands indicates coverage[4][7]",
    "regional_variations": "Phone intake differentiated by Oahu vs. neighbor islands, but no service differences noted[4][7]",
    "offices_or_providers": ["Main office: 924 Bethel Street, Honolulu, HI 96813-4304 (not open for walk-ins)[5][7]"]
  },
  "official_source": "https://www.legalaidhawaii.org/elder-law-services.html",
  "gotchas": ["Phone intake limited to specific hours (M-F 9-11:30AM & 1-3:30PM); no walk-in or public office access[4][7]", "Services free but limited to civil matters; priority to neediest may mean not all qualify or face waits[4][7]", "No fees, but does not handle criminal, business, personal injury, or fee-generating cases[4][7]", "Often confused with University of Hawaii Elder Law Program (UHELP), which is Oahu-only, student-supervised clinic with different contact (808-956-6544)[1][3][8]"],
  "data_shape_notes": "Statewide with island-specific intake lines; no detailed income/asset tables or forms listed; priority-based allocation due to high demand (serves 18,000+ clients yearly across Legal Aid)[5][7]; distinct from UHELP which is Oahu-restricted academic clinic"
}

{
  "name": "Long-Term Care Ombudsman Program (LTCOP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all residents of long-term care facilities regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Must be a resident (or acting on behalf of a resident) of a long-term care facility in Hawaii, such as nursing homes, assisted living facilities, adult residential care homes (ARCH), expanded ARCH, CCFFH, or similar settings."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Identifies, investigates, and resolves complaints related to action, inaction, or decisions adversely affecting health, safety, welfare, and rights; provides information, referral, and consultation on long-term care issues including alternatives to nursing home placement, payment options, choosing facilities, power of attorney/guardianship, refusing treatment, and resident rights; supports resident and family councils; conducts confidential face-to-face visits by certified ombudsmen (volunteers commit to weekly visits).",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 808-586-7268 (Oahu) or 1-888-229-2231 (statewide toll-free)", "Email: eoa.ltcop@doh.hawaii.gov", "Website: https://health.hawaii.gov/eoa/home/long-term-care-ombudsman-program/ or https://www.hi-ltc-ombudsman.org", "In-person: Contact via phone for local office arrangements; Executive Office on Aging at 250 S. Hotel St., Ste. 406, Honolulu, HI 96813"],
    "processing_time": "Not specified; complaint investigation begins promptly upon contact.",
    "waitlist": null,
    "forms": ["No specific application form required for services; submit complaints directly via phone/email; volunteer certification requires written application (details via 808-586-0100)."],
    "documents": ["No documents needed for services; for complaints, provide details of the issue, facility name, and resident information (with consent if required); volunteers need ID for background check, TB clearance."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services for residents of long-term care facilities across Hawaii; volunteer coordinators may be region-specific (e.g., Oahu-focused recruitment).",
    "regional_variations": "Primary contact numbers are Oahu-based (586-0100, 586-7268), with statewide toll-free line (1-888-229-2231); volunteer training and visits occur at facilities island-wide, but some recruitment emphasizes Oahu residency and vehicle access.",
    "offices_or_providers": ["Executive Office on Aging (EOA), Department of Health, Honolulu; statewide certified ombudsmen volunteers."]
  },
  "official_source": "https://health.hawaii.gov/eoa/home/long-term-care-ombudsman-program/",
  "gotchas": ["Not a direct service provider or financial aid program—offers advocacy and complaint resolution only, not healthcare or payment; requires resident consent for most actions (documented orally or in writing); confusion with volunteer recruitment (separate from receiving services); volunteers must reside locally (e.g., Oahu) with vehicle; not for non-facility residents unless seeking info/referral."],
  "data_shape_notes": "no income test; advocacy-only for LTC facility residents statewide; volunteer-driven with certification requirements; free and open to all qualifying residents without financial barriers"
}
